import { IMessageComposer } from '@nitrots/nitro-renderer';

export class SetTargetComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(targetUserId: number, lock: boolean) {
        this._data = [targetUserId, lock];
        console.log("target locked");
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {
        /* no-op */
    }
}
